+            let h = t_new - t;
+            h_abs = h.abs();
+
+            // Perform the RK step
+            let (y_new, f_new) = rk_step(fun, t, &self.y, &self.f, h, self.tableau, &mut self.k);
+            self.nfev += self.tableau.n_stages; // one eval per non-zero stage + final eval
