+                h_abs *= factor;
+                step_accepted = true;
+
+                self.y_old = Some(self.y.clone());
+                self.t_old = Some(t);
+                self.t = t_new;
+                self.y = y_new;
+                self.h_abs = h_abs;
+                self.f = f_new;
+            } else {
+                // Step rejected: decrease step size
+                h_abs *= MIN_FACTOR.max(SAFETY * err_norm.powf(self.error_exponent));
+                step_rejected = true;
+            }
+        }
