+    ($name:ident, $mode:expr, $cond:expr, $meta:expr, $anom:expr, $expected_action:expr) => {
+        #[test]
+        fn $name() {
+            let mut ctrl = PolicyController::new($mode, 16);
+            let d = ctrl.decide(DecisionSignals::new($cond, $meta, $anom));
+            assert_eq!(d.action, $expected_action);
+        }
+    };
+}
