+        let cond = i as f64 * 0.5;
+        let d = ctrl.decide(DecisionSignals::new(cond, 0.0, 0.0));
+        if d.action == PolicyAction::FullValidate {
+            saw_validate = true;
+        }
+    }
+    assert!(saw_validate, "must eventually full-validate as condition rises");
+}
